const input = $input.first().json;
const path = input.body?.photo_path || input.photo_path || '';
const size = input.body?.size || input.size || 0;
const ts = input.body?.timestamp || input.timestamp || '';

console.log(`New photo: ${path} (${size} bytes)`);

return [{json: {
  status: 'ok',
  photo_path: path,
  size: size,
  timestamp: ts,
  message: `Photo saved: ${path}`
}}];
